import matchms; from rdkit import Chem; from rdkit.Chem import Descriptors; import json; spectra = matchms.importing.load_spectra('{inputs.0}'); cleaned = []; 
for spec in spectra:
    if 'smiles' in spec.metadata and '.' in spec.metadata.get('smiles', ''):
        salt_smiles = spec.metadata['smiles'].split('.')
        parent_mass = float(spec.metadata.get('precursor_mz', 0))
        matched = False
        for ion_smiles in salt_smiles:
            mol = Chem.MolFromSmiles(ion_smiles)
            if mol:
                mass = Descriptors.MonoisotopicMass(mol)
                if abs(mass - parent_mass) < 0.01:
                    spec.metadata['smiles'] = ion_smiles
                    spec.metadata['smiles_repaired'] = True
                    matched = True
                    break
        if not matched:
            spec.metadata['smiles_repaired'] = False
    cleaned.append(spec)
matchms.exporting.save_spectra(cleaned, 'cleaned_library.json')
